create table dirkspzm32.isi_user (
    sid            varchar2(2 char) default '01' not null enable,
    firma_nr       number(2, 0) default 1 not null enable,
    login_id       number(*, 0) not null enable,
    username       varchar2(50 char),
    passwort       varchar2(20 char),
    transponder    varchar2(255 char),
    pers_nr        number(*, 0),
    anrede         varchar2(20 char),
    nachname       varchar2(255 char),
    vorname        varchar2(255 char),
    anschrift      varchar2(255 char),
    plz            number(5, 0),
    wohnort        varchar2(255 char),
    telefon_nr     varchar2(50 char),
    kuerzel        varchar2(5 char),
    sprache        number(*, 5) default 1 not null enable,
    security_level number(*, 5),
    adress_id      number(*, 0),
    email          varchar2(255 char),
    fax            varchar2(50 char)
);

alter table dirkspzm32.isi_user
    add constraint pk_isi_user primary key ( login_id )
        using index enable;

alter table dirkspzm32.isi_user add constraint u_isi_user_pers_nr unique ( pers_nr )
    using index enable;

alter table dirkspzm32.isi_user add constraint u_isi_user_transponder unique ( transponder )
    using index enable;

alter table dirkspzm32.isi_user add constraint u_isi_user_username unique ( username )
    using index enable;


